algorithm:
Modified greedy insertion with fallback: evaluate all existing routes plus one empty route per unassigned order using a simple cost heuristic, then insert into the best feasible route; if none exists, create a new assign and insert there.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderCount := len(oris)
	for oIdx := 0; oIdx < orderCount; oIdx++ {
		bestAssignIdx := -1
		bestDeltaCost := 1e308
		ori := oris[oIdx]
		des := dess[oIdx]
		shipID := total_ship + oIdx

		maxTries := dispatch.AssignsLen + 1
		for tryIdx := 0; tryIdx < maxTries; tryIdx++ {
			assignPtr := &dispatch.Assigns[tryIdx]
			oldCost := assignPtr.Cost
			added := false
			if tryIdx < dispatch.AssignsLen || (tryIdx == dispatch.AssignsLen && tryIdx < MAXASSIGNS) {
				added = assignPtr.AddShip(shipID, ori, des)
				if added {
					assignPtr.GenRoute()
					newCost := assignPtr.Cost
					delta := newCost - oldCost
					if delta >= 0 && newCost >= 0 && (delta < bestDeltaCost || bestAssignIdx == -1) {
						bestDeltaCost = delta
						bestAssignIdx = tryIdx
					}
					assignPtr.RemoveShip(shipID)
					assignPtr.GenRoute()
				}
			}
		}

		if bestAssignIdx >= 0 {
			target := &dispatch.Assigns[bestAssignIdx]
			ok := target.AddShip(shipID, ori, des)
			if ok {
				target.GenRoute()
				if bestAssignIdx >= dispatch.AssignsLen && bestAssignIdx < MAXASSIGNS {
					dispatch.AssignsLen++
				}
			}
		} else {
			fallbackIdx := dispatch.AssignsLen
			if fallbackIdx < MAXASSIGNS {
				target := &dispatch.Assigns[fallbackIdx]
				ok := target.AddShip(shipID, ori, des)
				if ok {
					target.GenRoute()
					dispatch.AssignsLen++
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

